1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty grid for empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should return empty grid for single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should return empty grid for two live cells (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a live cell alive when it has exactly 2 live neighbors", () => {
15	    expect(nextGeneration([[0, 1], [1, 1], [2, 1]])).toEqual([[1, 1]]);
16	  });
17	  it("should keep a live cell alive when it has exactly 3 live neighbors", () => {
18	    // (1,0) has 3 neighbors: (0,0),(2,0),(1,1); all cells have 2 or 3 neighbors and survive
19	    expect(nextGeneration([[0, 0], [1, 0], [2, 0], [1, 1]])).toEqual([[0, 0], [1, 0], [2, 0], [1, 1]]);
20	  });
21	  it("should kill a live cell with more than 3 live neighbors (overpopulation)", () => {
22	    // center (1,1) has 5 neighbors: (0,0),(1,0),(2,0),(0,1),(2,1) - dies
23	    // (1,0) also has 5 neighbors - dies; others have 3 neighbors - survive
24	    expect(nextGeneration([[0, 0], [1, 0], [2, 0], [0, 1], [2, 1], [1, 1]])).toEqual([[0, 0], [2, 0], [0, 1], [2, 1]]);
25	  });
26	  it.todo("should make a dead cell alive when it has exactly 3 live neighbors (reproduction)");
27	  it.todo("should keep a 2x2 block unchanged (still life)");
28	});
29

1	export type Cell = [number, number];
2	
3	const countNeighbors = (cell: Cell, cells: Cell[]): number =>
4	  cells.filter(
5	    ([r, c]) => Math.abs(r - cell[0]) <= 1 && Math.abs(c - cell[1]) <= 1 && !(r === cell[0] && c === cell[1])
6	  ).length;
7	
8	export function nextGeneration(cells: Cell[]): Cell[] {
9	  return cells.filter((cell) => {
10	    const neighborCount = countNeighbors(cell, cells);
11	    return neighborCount === 2 || neighborCount === 3;
12	  });
13	}
